previewCss:
.darma-loader-darma-custom-452 {color: var(--loader-color, #dc2626);
  --loader-secondary-color: var(--loader-secondary-color, #f97316);
  --loader-bg: var(--loader-bg, #ffffff);
   display: inline-flex;
   gap: 5px;
   animation: darma-loader-darma-custom-452-l2-0 1s infinite linear;
}
.darma-loader-darma-custom-452:before, .darma-loader-darma-custom-452:after  {
  content: "";
   width: 35px;
   aspect-ratio: 1;
   box-shadow: 0 0 0 3px inset currentColor;
   animation: darma-loader-darma-custom-452-l2-1 1s infinite linear both;
}
.darma-loader-darma-custom-452:after  {
  animation-direction:reverse;
}
@keyframes darma-loader-darma-custom-452-l2-0 {
  0% {transform:rotate(0deg)}
80%, 100%{transform:rotate(180deg)}
}
@keyframes darma-loader-darma-custom-452-l2-1 {
  0%, 20% {border-radius:0}
80%, 100% {border-radius:50%}
}

